/**
 * Replicate API firewall config generator.
 *
 * Data source: https://replicate.com/docs/reference/http
 *
 * Replicate uses Bearer token authentication.
 * Token format: r8_ prefix followed by 36 alphanumeric characters.
 */

import { writeOutput } from "./codegen";

const DOCS_URL = "https://replicate.com/docs/reference/http";
// Format: r8_ + 36 alphanumeric chars
const PLACEHOLDER_VALUE = "r8_CoffeeSafeLocalCoffeeSafeLocalCoffee";

function generateTypeScript(): string {
  const lines: string[] = [
    "// Auto-generated from Replicate API docs.",
    `// Source: ${DOCS_URL}`,
    "// Regenerate: cd turbo && pnpm -F @vm0/firewalls-generator generate:replicate",
    "//",
    "// DO NOT EDIT THIS FILE MANUALLY.",
    "",
    'import type { FirewallConfig } from "../firewall-types";',
    "",
    "export const replicateFirewall = {",
    '  name: "replicate",',
    '  description: "Replicate",',
    "  placeholders: {",
    `    REPLICATE_TOKEN: "${PLACEHOLDER_VALUE}",`,
    "  },",
    "  apis: [",
    "    {",
    '      base: "https://api.replicate.com",',
    "      auth: {",
    "        headers: {",
    '          Authorization: "Bearer ${{ secrets.REPLICATE_TOKEN }}",',
    "        },",
    "      },",
    "      permissions: [],",
    "    },",
    "  ],",
    "} as const satisfies FirewallConfig;",
    "",
  ];
  return lines.join("\n");
}

export async function generate(): Promise<void> {
  console.error("Generating Replicate firewall config...");
  const ts = generateTypeScript();
  writeOutput("replicate", ts, import.meta.dirname);
}
